import React from 'react';
import merge from 'classnames';

import { Input } from 'components';

import { Props, State } from './SearchInput.types';
import styles from './SearchInput.module.scss';

export class SearchInput extends React.Component<Props, State> {
  state: State = {
    value: '',
  };

  // Event handlers

  onSearchValueChange = (event: React.ChangeEvent<HTMLInputElement>): void => {
    this.setState({ value: event.target.value });
  };

  // RENDER

  render() {
    const { className, ...props } = this.props;

    return (
      <Input
        {...props}
        type="text"
        color="green"
        placeholder="search"
        value={this.state.value}
        onChange={this.onSearchValueChange}
        className={merge(styles.input, className)}
      />
    );
  }
}
