import React from 'react';
import merge from 'classnames';

import { Button, Image } from 'components';

import { Hamburger, SearchInput } from './components';
import { State } from './Header.types';
import styles from './Header.module.scss';

export class Header extends React.Component<{}, State> {
  state: State = { isMobileMenuOpened: false };

  // Component lifecycle methods

  componentDidUpdate() {
    const { isMobileMenuOpened } = this.state;
    document.getElementById('root')!.classList[isMobileMenuOpened ? 'add' : 'remove']('no-scroll');
  }

  // Action handlers

  toggleMobileMenu = (): void => {
    this.setState((prevState: State) => ({ isMobileMenuOpened: !prevState.isMobileMenuOpened }));
  };

  // Event handlers

  onLogoClick = (): void => {
    console.log('redirect to "Home" page');
  };

  onLoginButtonClick = (): void => {
    console.log('login user');
  };

  // RENDER

  render() {
    const { isMobileMenuOpened } = this.state;

    return (
      <header className={styles.header}>
        <div className={styles.left}>
          <div className={styles.title} onClick={this.onLogoClick}>
            <Image
              src="images/application_logo.png"
              alt="Poku Art Challenge logo"
              pixelRatio={2}
              className={merge(styles.logo, styles.no_desktop)}
            />

            <span>Poku Art Challenge</span>
          </div>

          <SearchInput />
        </div>

        <div className={styles.right}>
          <Button
            color="transparent"
            onClick={this.onLoginButtonClick}
            className={merge(styles.button, styles.no_desktop)}
          >
            Log in
          </Button>

          <Hamburger active={isMobileMenuOpened} onClick={this.toggleMobileMenu} />
        </div>
      </header>
    );
  }
}
