import React from 'react';

import { Props } from './Image.types';

export const Image = ({ pixelRatio, ...props }: Props) => {
  if (pixelRatio) {
    // Split string by last DOT “.”
    const [path, ext] = props.src.split(/\.(?=[^.]+$)/);

    // Add srcset image attribute to all image props
    props.srcSet = '';
    for (let i = 1; i <= pixelRatio; i++) {
      if (i === 1) {
        props.srcSet += `${path}.${ext} 1x`;
      } else {
        props.srcSet += `, ${path}@${i}x.${ext} ${i}x`;
      }
    }
  }

  return <img alt="" {...props} />;
};
